class BookMyShow {

    int[] seats;
    int n, m;

    public BookMyShow(int n, int m) {
        this.n = n;
        this.m = m;
        seats = new int[n][m];
        for (int i = 0; i < n; i++) {
            Arrays.fill(seats[i], 1);
        }
    }

    public int[] gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (seats[i].length >= k) {
                int start = seats[i][0] - 1;
                if (start + k <= seats[i].length) {
                    return new int[]{i, start};
                }
            }
        }
        return new int[0];
    }

    public boolean scatter(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (seats[i].length >= k) {
                for (int j = 0; j < seats[i].length - k + 1; j++) {
                    if (seats[i][j] == 1) {
                        for (int l = 0; l < k; l++) {
                            seats[i][j + l] = 0;
                        }
                        return true;
                    }
                }
            }
        }
        return false;
    }
}
```
